-- Lessons: Начало работы (manager-start)
INSERT INTO learning_lessons (module_id, slug, title, duration, sort_order, sections, next_action_label, next_action_href) VALUES
('manager-start', 'leader-welcome', 'Обзор платформы для руководителя', '4 мин', 1,
 '[{"heading":"Ваш кабинет руководителя","body":"Как руководитель профсоюза вы управляете членами вашей организации через платформу «Мой Профсоюз». В вашем кабинете:\n\n- **Дашборд** — сводка по членам, обращениям и подразделениям\n- **Члены профсоюза** — список, фильтры, карточки членов\n- **Обращения** — все обращения ваших членов\n- **Диалоги** — переписка с членами\n- **Объявления** — массовые рассылки\n- **Документы** — документы членов\n- **Приглашения** — статистика привлечения"},{"heading":"Первые шаги","body":"1. **Ознакомьтесь с дашбордом** — там сводка по всем направлениям\n2. **Проверьте список членов** — убедитесь, что все привязаны к вам\n3. **Проверьте незакреплённых** — закрепите за собой новых членов\n4. **Настройте Telegram** — чтобы получать уведомления о новых обращениях\n5. **Сделайте первое объявление** — поприветствуйте членов на платформе"},{"heading":"Подразделения","body":"Платформа поддерживает структуру подразделений (ППО). Вы можете:\n\n- Фильтровать членов по подразделению\n- Отправлять объявления по подразделению\n- Видеть аналитику по подразделениям на дашборде"}]',
 'Перейти к членам', '/manager/agents'),

('manager-start', 'leader-members', 'Управление членами профсоюза', '3 мин', 2,
 '[{"heading":"Список членов","body":"В разделе **Члены профсоюза** вы видите всех закреплённых за вами членов. Доступно:\n\n- **Поиск** по имени и email\n- **Фильтры** по подразделению, полу, возрасту, городу, профессии\n- **Вкладки** по сегментам: все, обучаются, готовы, активные, проблемные\n- **Сортировка** по дате, имени, возрасту, обращениям"},{"heading":"Карточка члена","body":"Нажмите на строку в таблице, чтобы открыть карточку члена. Там вы увидите:\n\n- Контактные данные и подразделение\n- Статус жизненного цикла\n- Прогресс обучения\n- Список обращений этого члена\n- Кнопки управления (активация/деактивация)"},{"heading":"Незакреплённые члены","body":"Если в системе есть незакреплённые члены (без руководителя), вы увидите кнопку **Незакреплённые** в правом верхнем углу. Вы можете:\n\n- Закрепить по одному\n- Закрепить всех незакреплённых разом"}]');

-- Lessons: Обращения (manager-leads)
INSERT INTO learning_lessons (module_id, slug, title, duration, sort_order, sections, next_action_label, next_action_href) VALUES
('manager-leads', 'leader-appeals', 'Работа с обращениями', '4 мин', 1,
 '[{"heading":"Виды обращений","body":"Члены профсоюза подают 4 типа обращений:\n\n- **Консультация** — вопрос по трудовым правам\n- **Жалоба** — сообщение о нарушении прав\n- **Заявка** — запрос помощи или действия\n- **Инициатива** — предложение по улучшению\n\nВы можете фильтровать обращения по типу и подразделению."},{"heading":"Статусы обращений","body":"Вы управляете статусами обращений:\n\n- **Новое** → **Принято** — вы взяли в работу\n- **Принято** → **Подтверждено** — проверили обращение\n- **Подтверждено** → **На согласовании** — работаете с работодателем/третьими сторонами\n- **На согласовании** → **В работе** — активная работа\n- **В работе** → **Решено** — вопрос решён\n- Любой → **Закрыто** — если обращение неактуально\n\nМеняйте статус через выпадающий список на странице обращения."},{"heading":"Конфликты и дубли","body":"Если система обнаруживает потенциальный дубль (совпадение по телефону или email), обращение помечается как конфликтное. Вы можете:\n\n- Подтвердить дубль\n- Отметить как разные обращения\n- Переназначить ответственного"}]',
 'Перейти к обращениям', '/manager/leads');

-- Lessons: Коммуникации (manager-comms)
INSERT INTO learning_lessons (module_id, slug, title, duration, sort_order, sections, next_action_label, next_action_href) VALUES
('manager-comms', 'leader-comms', 'Диалоги и объявления', '3 мин', 1,
 '[{"heading":"Диалоги с членами","body":"В разделе **Диалоги** вы видите все переписки с членами профсоюза. Вы можете:\n\n- Отвечать на сообщения\n- Видеть AI-классификацию сообщений\n- Использовать AI-подсказки для ответов\n- Фильтровать: все, активные, требующие внимания, эскалации\n\nЕсли у члена подключён Telegram, ваши сообщения придут ему прямо в мессенджер."},{"heading":"Объявления","body":"Раздел **Объявления** позволяет отправлять массовые сообщения. Вы можете рассылать:\n\n- **Всем своим членам**\n- **Активным** — у кого есть обращения\n- **По подразделению** — выбираете конкретное ППО\n- **Вручную** — выбираете конкретных людей\n\nКаналы: через платформу, через Telegram или оба."},{"heading":"Советы по коммуникации","body":"- Отвечайте на обращения в течение 1-3 дней\n- Используйте объявления для информирования о важных событиях\n- Обращения с типом «Жалоба» рассматривайте приоритетно\n- Подключите Telegram для оперативных уведомлений"}]',
 'Перейти к диалогам', '/manager/conversations');

-- Lessons: Документы (manager-finance-docs)
INSERT INTO learning_lessons (module_id, slug, title, duration, sort_order, sections, next_action_label, next_action_href) VALUES
('manager-finance-docs', 'leader-docs', 'Работа с документами членов', '2 мин', 1,
 '[{"heading":"Документы на платформе","body":"В разделе **Документы** вы видите все документы, загруженные вашими членами:\n\n- Заявления\n- Справки\n- Акты\n- Договоры\n\nВы можете искать по названию документа или имени владельца."},{"heading":"Загрузка документов","body":"Вы также можете загружать документы для членов:\n\n1. Перейдите в раздел **Документы**\n2. Прокрутите до блока **Загрузка**\n3. Перетащите файл или нажмите для выбора\n\nФорматы: PDF, DOC, DOCX, JPG, PNG. Максимум 10 МБ."}]',
 'Перейти к документам', '/manager/documents');

-- Lessons: FAQ (manager-faq)
INSERT INTO learning_lessons (module_id, slug, title, duration, sort_order, sections) VALUES
('manager-faq', 'leader-faq', 'FAQ для руководителей', '4 мин', 1,
 '[{"heading":"Как закрепить за собой новых членов?","body":"Перейдите в **Члены профсоюза** → нажмите **Незакреплённые** → закрепите по одному или всех сразу кнопкой «Закрепить всех»."},{"heading":"Как отправить объявление по подразделению?","body":"Перейдите в **Объявления** → **Создать** → выберите аудиторию «По подразделению» → выберите нужное ППО → напишите текст → отправьте."},{"heading":"Как фильтровать обращения?","body":"В разделе **Обращения** используйте:\n- Фильтр по типу обращения (жалоба, заявка, инициатива, консультация)\n- Фильтр по подразделению\n- Вкладки по статусу (новые, в работе, завершённые)"},{"heading":"Как изменить статус обращения?","body":"Откройте обращение → в верхней части страницы есть выпадающий список с текущим статусом → выберите новый → статус обновится автоматически."},{"heading":"Что делать если член профсоюза не активен?","body":"В карточке члена нажмите **Деактивировать** — он будет перемещён в сегмент «Проблемные». При необходимости можно вернуть, нажав **Активировать**."},{"heading":"Как посмотреть аналитику по подразделениям?","body":"На **Дашборде** внизу есть таблица «Подразделения» с количеством членов и обращений по каждому ППО."}]');
